namespace sv_b769f0540ac444ba98935fddcf287649.Services;

public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> RecipesByCuisine = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Spaghetti Carbonara", "Classic Roman pasta with eggs, pecorino, guanciale, and black pepper.", 25),
            new(2, "Margherita Pizza", "Traditional Neapolitan pizza with tomato, mozzarella, and fresh basil.", 45),
            new(3, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan.", 35),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Tender chicken pieces in a creamy spiced tomato sauce.", 40),
            new(5, "Palak Paneer", "Fresh spinach cooked with paneer cheese and aromatic spices.", 30),
            new(6, "Biryani", "Fragrant layered rice dish with marinated meat and whole spices.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Spit-grilled pork tacos with pineapple, cilantro, and onion.", 50),
            new(8, "Guacamole", "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", 10),
            new(9, "Enchiladas Verdes", "Corn tortillas filled with chicken and bathed in green tomatillo salsa.", 35),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (RecipesByCuisine.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@using sv_b769f0540ac444ba98935fddcf287649.Services
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_isRefreshing && _recipes is not null)
{
    <p><em>Refreshing…</em></p>
}

@if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in GetSortedRecipes())
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _errorMessage;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        // Only reload when cuisine changes, not when sort changes
        if (_loadedCuisineId == CuisineId && _recipes is not null)
        {
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _errorMessage = null;
        _isRefreshing = _recipes is not null;

        if (!_isRefreshing)
        {
            _recipes = null;
        }

        var cuisineId = CuisineId;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(cuisineId, token);
            _recipes = results;
            _loadedCuisineId = cuisineId;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Request was superseded; do nothing
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineId);
            _errorMessage = "The request timed out. Please try again.";
            _isRefreshing = false;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineId);
            _errorMessage = "The request timed out. Please try again.";
            _isRefreshing = false;
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", cuisineId);
            _errorMessage = "Something went wrong loading recipes. Please try again.";
            _isRefreshing = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null) return Enumerable.Empty<Recipe>();

        return Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes.OrderByDescending(r => r.Id),
            "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
            _ => _recipes,
        };
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

